<?php require_once __DIR__ . '/../includes/admin.php';admin_required();$error='';if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf($_POST['csrf']??null);try{$name=trim($_POST['customer_name']??'');$review=trim($_POST['review']??'');$rating=(int)($_POST['rating']??0);if(mb_strlen($name)<2||mb_strlen($review)<5||$rating<1||$rating>5)throw new RuntimeException('Enter a customer name, review and rating.');db()->prepare('INSERT INTO testimonials (customer_name,review,rating,approved) VALUES (?,?,?,?)')->execute([$name,$review,$rating,isset($_POST['approved'])?1:0]);redirect('admin/testimonials.php');}catch(Throwable $e){$error=$e->getMessage();}}$items=db()->query('SELECT * FROM testimonials ORDER BY created_at DESC')->fetchAll();admin_head('Testimonials'); ?><h1>Testimonials</h1><form class="card" method="post"><h2>Add testimonial</h2><?php if($error):?><p class="error"><?=e($error)?></p><?php endif?><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input name="customer_name" placeholder="Customer name" required><textarea name="review" placeholder="Review" required></textarea><select name="rating"><?php for($i=5;$i>=1;$i--):?><option value="<?=$i?>"><?=$i?> stars</option><?php endfor?></select><label><input style="width:auto" type="checkbox" name="approved" checked> Publish now</label><br><button>Add testimonial</button></form><div class="card"><table><tr><th>Customer</th><th>Review</th><th>Rating</th><th>Published</th></tr><?php foreach($items as $item):?><tr><td><?=e($item['customer_name'])?></td><td><?=e($item['review'])?></td><td><?=e($item['rating'])?>/5</td><td><?=$item['approved']?'Yes':'No'?></td></tr><?php endforeach?></table></div><?php admin_foot(); ?>
